                                    </div>

                                    {/* Filas de la Gantt */}
                                    <div className="max-h-[600px] overflow-y-auto custom-scrollbar divide-y divide-slate-100">
                                        {ganttData.length === 0 ? (
                                            <div className="p-16 text-center text-slate-400 font-medium">No hay microprocesos activos para mostrar en la Gantt.</div>
                                        ) : ganttData.map((group, gIdx) => (
                                            <div key={gIdx} className="grid grid-cols-[280px_1fr] group">
                                                <div className="p-3 border-r border-slate-200 bg-slate-50/20 group-hover:bg-indigo-50/30 transition-colors">
                                                    <div className="flex items-center gap-2 mb-1">
                                                        <span className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100">{group.project}</span>
                                                    </div>
                                                    <p className="text-xs font-bold text-slate-700 truncate" title={group.micro}>{group.micro}</p>
                                                </div>
                                                <div className="p-3 space-y-1.5 relative bg-white group-hover:bg-slate-50/50 transition-colors">
                                                    {group.items.map((doc, dIdx) => {
                                                        const isStuck = doc.durationDays > 45 && doc.state !== DocState.APPROVED;
                                                        return (
                                                            <div key={dIdx} className="flex items-center gap-3 h-4">
                                                                <span className="text-[8px] font-black text-slate-400 w-8 text-right shrink-0">{doc.docType}</span>
                                                                <div className="flex-1 relative h-2.5">
                                                                    {/* Línea de guía 45 días */}
                                                                    <div className="absolute top-0 bottom-0 border-l border-dashed border-red-200/50" style={{ left: `${Math.min(100, (doc.offsetDays + 45) * 1.6)}%` }}></div>

                                                                    {/* Barra de progreso */}
                                                                    <div 
                                                                        onClick={() => navigate(`/doc/${doc.id}`)}
                                                                        className={`absolute h-full rounded-full transition-all cursor-pointer shadow-sm hover:ring-2 hover:ring-indigo-300 flex items-center justify-end px-1.5 ${
                                                                            doc.state === DocState.APPROVED ? 'bg-green-500' :
                                                                            [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(doc.state) ? 'bg-purple-500' : 
                                                                            doc.state === DocState.NOT_STARTED ? 'bg-slate-200' : 'bg-blue-500'
                                                                        } ${isStuck ? 'ring-1 ring-red-400 animate-pulse' : ''}`}
                                                                        style={{ 
                                                                            left: `${Math.min(98, doc.offsetDays * 1.6)}%`, 
                                                                            width: `${Math.min(100, doc.durationDays * 1.6)}%` 
                                                                        }}
                                                                        title={`${doc.docType}: ${doc.durationDays} días activo`}
                                                                    >
                                                                        {doc.durationDays > 10 && (
                                                                            <span className="text-[6px] font-bold text-white uppercase">{doc.durationDays}d</span>
                                                                        )}
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        ))}
                                    </div>

                                    {/* Footer Legend */}
                                    <div className="p-4 bg-slate-50 text-[10px] text-slate-400 italic flex items-center justify-center gap-6 border-t border-slate-200">
                                        <div className="flex items-center gap-1.5"><Info size={12} /> Las barras muestran la duración relativa desde la creación del registro.</div>
                                        <div className="flex items-center gap-1.5"><ShieldAlert size={12} className="text-red-400" /> El parpadeo rojo indica procesos que han excedido los 45 días de maduración.</div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </section>
                )}
            </div>
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
