                                                                        style={{ left: `${Math.max(0, left)}%`, width: `${Math.max(2, width)}%`, opacity: doc.state === DocState.NOT_STARTED ? 0.3 : 1 }}
                                                                        title={`${doc.docType}: ${STATE_CONFIG[doc.state].label}`}
                                                                    ></div>
