                                                <div className="p-3 border-r border-slate-200 bg-slate-50/20 group-hover:bg-indigo-50/30 transition-colors">
                                                    <div className="flex items-center gap-2 mb-0.5"><span className="text-[8px] font-black text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100 uppercase">{group.project}</span></div>
                                                    <p className="text-xs font-bold text-slate-700 truncate">{group.micro}</p>
                                                </div>
                                                <div className="p-2 space-y-1 relative bg-white group-hover:bg-slate-50/50 transition-colors">
                                                    {group.items.map((doc, dIdx) => {
                                                        let left = 0; let width = 0;
                                                        if (ganttScale === 'MONTHS') {
                                                            if (!doc.isVisibleInYear) return null;
                                                            left = (doc.mStart / 12) * 100;
                                                            width = ((doc.mEnd - doc.mStart + 1) / 12) * 100;
                                                        } else {
                                                            left = ((doc.yStart + 1) / 3) * 100;
                                                            width = ((doc.yEnd - doc.yStart + 1) / 3) * 100;
                                                        }
                                                        if (width <= 0) return null;
                                                        return (
                                                            <div key={dIdx} className="flex items-center gap-3 h-3.5">
                                                                <span className="text-[7px] font-black text-slate-400 w-8 text-right shrink-0">{doc.docType}</span>
                                                                <div className="flex-1 relative h-2">
                                                                    <div onClick={() => navigate(`/doc/${doc.id}`)} className={`absolute h-full rounded-full transition-all cursor-pointer shadow-sm hover:ring-2 hover:ring-indigo-300 ${STATE_CONFIG[doc.state].color.includes('green') ? 'bg-green-500' : [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(doc.state) ? 'bg-purple-500' : doc.state === DocState.NOT_STARTED ? 'bg-slate-200' : 'bg-blue-500'}`} style={{ left: `${Math.max(0, left)}%`, width: `${Math.max(2, width)}%`, opacity: doc.state === DocState.NOT_STARTED ? 0.3 : 1 }}></div>
                                                                </div>
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </section>
                )}
            </div>
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', green: 'bg-green-50 text-green-600 border-green-100', amber: 'bg-amber-50 text-amber-600 border-amber-100', slate: 'bg-slate-50 text-slate-600 border-slate-100' };
    return ( <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md transition-all active:scale-95' : ''}`}> <div className="flex justify-between items-start mb-2"><span className="text-[9px] font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={16} /></div> <div><span className="text-xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[9px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={10} className="opacity-60" />}</div></div> </div> );
};

const AgileBucket = ({ title, value, icon: Icon, color, onClick }: any) => {
    const colorMap: Record<string, string> = { slate: 'bg-slate-50 text-slate-700 border-slate-200 hover:bg-slate-100', blue: 'bg-blue-50 text-blue-700 border-blue-200 hover:bg-blue-100', purple: 'bg-purple-50 text-purple-700 border-purple-200 hover:bg-purple-100', orange: 'bg-orange-50 text-orange-700 border-orange-200 hover:bg-orange-100', green: 'bg-green-50 text-green-700 border-green-200 hover:bg-green-100' };
    return ( <div onClick={onClick} className={`p-3 rounded-xl border cursor-pointer transition-all active:scale-95 flex flex-col items-center text-center shadow-sm ${colorMap[color]}`}> <div className="p-2 rounded-full bg-white/50 mb-2"><Icon size={18} /></div> <span className="text-[10px] font-bold uppercase tracking-wide opacity-80">{title}</span> <span className="text-xl font-extrabold">{value}</span> </div> );
};

export default Reports;
